// src/ai/aiService.js

// Small delay to simulate AI
function delay(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

// ──────────────────────────────────────────────
// 1. SUMMARY
// ──────────────────────────────────────────────
export async function generateSummary(title, content) {
  await delay(800);

  return `This article explores ${title.toLowerCase()} in a clear and practical way. 
It highlights key ideas and provides useful insights. 
Overall, it helps readers better understand the topic.`;
}

// ──────────────────────────────────────────────
// 2. WRITING ANALYSIS
// ──────────────────────────────────────────────
export async function analyzeWriting(title, content) {
  await delay(1000);

  const lengthScore = Math.min(10, Math.floor(content.length / 80));

  return {
    score: lengthScore || 7,
    tone: "Professional",
    readability: content.length > 300 ? "Medium" : "Easy",
    strengths: [
      "Clear topic selection",
      "Good structure",
      "Engaging content",
    ],
    improvements: [
      "Add real-world examples",
      "Improve introduction",
      "Break long paragraphs",
    ],
    rewrittenIntro: `In today's fast-changing world, ${title.toLowerCase()} is becoming increasingly important. This article explores it in a simple and practical way.`,
  };
}

// ──────────────────────────────────────────────
// 3. SMART TAG GENERATOR (🔥 FIXED)
// ──────────────────────────────────────────────
export async function generateTags(title, content) {
  await delay(600);

  const text = (title + " " + content).toLowerCase();

  // common tech/content keywords
  const keywords = [
    "react",
    "firebase",
    "javascript",
    "web",
    "frontend",
    "backend",
    "ai",
    "machine learning",
    "design",
    "ui",
    "ux",
    "api",
    "database",
    "cloud",
    "security",
    "performance",
    "optimization",
    "tutorial",
    "guide",
    "blog",
    "content",
  ];

  let tags = [];

  // match keywords in text
  keywords.forEach((word) => {
    if (text.includes(word)) {
      tags.push(word.replace(" ", "-"));
    }
  });

  // fallback: extract most frequent meaningful words
  if (tags.length === 0) {
    const words = text.split(/\W+/);

    const freq = {};
    words.forEach((w) => {
      if (w.length > 4) {
        freq[w] = (freq[w] || 0) + 1;
      }
    });

    tags = Object.entries(freq)
      .sort((a, b) => b[1] - a[1])
      .map(([word]) => word)
      .slice(0, 5);
  }

  // remove duplicates + limit
  return [...new Set(tags)].slice(0, 5);
}

// ──────────────────────────────────────────────
// 4. COMMENT SENTIMENT
// ──────────────────────────────────────────────
export async function analyzeCommentSentiment(commentText) {
  await delay(500);

  return {
    sentiment: "Positive",
    emotion: "Happy",
    toxic: false,
    score: 0.8,
    flag: "none",
  };
}

// ──────────────────────────────────────────────
// 5. RECOMMENDATIONS
// ──────────────────────────────────────────────
export async function getRecommendations(readHistory, allPosts) {
  await delay(500);

  return allPosts.slice(0, 3);
}
